import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def get_pkgs(data):
    pkgs = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                pkgs[(name, pkg['id'])] = pkg['resolvedVersion']
    return pkgs

b, a = get_pkgs(baseline), get_pkgs(after)
changes = [(k, b[k], a[k]) for k in b if b[k] != a.get(k)]
missing = [k for k in b if k not in a]
added = [k for k in a if k not in b]
if not changes and not missing and not added:
    print('All packages resolve identically to baseline.')
else:
    for c in changes: print(f'CHANGED: {c}')
    for m in missing: print(f'MISSING: {m}')
    for x in added: print(f'ADDED: {x}')
"

